const hexStr = '\\';

function hexToBase64String(hexString) {
  let hex = hexString.startsWith('\\x') ? hexString.slice(2) : hexString;
  let str = '';
  for (let i = 0; i < hex.length; i += 2) {
    str += String.fromCharCode(parseInt(hex.substr(i, 2), 16));
  }
  return str;
}

const recoveredBase64 = hexToBase64String(hexStr);
console.log("Recovered base64:", recoveredBase64);
console.log("Is it standard base64?", /^[a-zA-Z0-9+/=]+$/.test(recoveredBase64));
